dleplugin.notice:
.htaccess
Найти:
RewriteRule ^sitemap.xml$ uploads/sitemap.xml [L]
Ниже вставить:
RewriteRule ^([0-9]+)/([^/]+)(/?)+$ index.php?newsid=$1&fullpage=$2 [L]
RewriteRule ^([0-9]+)/([^/]+)/page/([0-9]+)(/?)+$ index.php?newsid=$1&fullpage=$2&cstart=$3 [L]
RewriteRule ^([0-9]+)-([^/]+)/([^/]+)(/?)+$ index.php?newsid=$1&fullurl=$2&fullpage=$3 [L]
RewriteRule ^([0-9]+)-([^/]+)/([^/]+)/page/([0-9]+)(/?)+$ index.php?newsid=$1&fullurl=$2&fullpage=$3&cstart=$4 [L]

Или для nginx:
rewrite ^/([0-9]+)/([^/]+)/*$ /index.php?newsid=$1&fullpage=$2 last;
rewrite ^/([0-9]+)/([^/]+)/page/([0-9]+)/*$ /index.php?newsid=$1&fullpage=$2&cstart=$3 last;
rewrite ^/([0-9]+)-([^/]+)/([^/]+)/*$ /index.php?newsid=$1&fullurl=$2&fullpage=$3 last;
rewrite ^/([0-9]+)-([^/]+)/([^/]+)/page/([0-9]+)/*$ /index.php?newsid=$1&fullurl=$2&fullpage=$3&cstart=$4 last;

operation.replacecode:
if (isset($fullpage)) {
	$tpl->copy_template = preg_replace_callback('#\\[(not-)?fullpage=(.+?)\\](.*?)\\[/\\1?fullpage\\]#is', function($m) use ($fullpage){
		if ($m[1]) {
			return $fullpage->getPageName() != $m[2] ? $m[3] : '';
		} else {
			return $fullpage->getPageName() == $m[2] ? $m[3] : '';
		}
	}, $tpl->copy_template);
} else {
	$tpl->copy_template = preg_replace('#\\[(not-)?fullpage=.+?\\].*?\\[/\\1?fullpage\\]#is', '', $tpl->copy_template);
}
